#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

/*
 * Operating System Concept: Process Management
 * Demonstrates: fork(), exec(), process hierarchy, zombie/orphan states
 */

void demonstrate_process_creation() {
 pid_t pid;
 int status;

 printf("=== Process Management Demo ===\n\n");

 // Parent process creates a child using fork()
 printf("Parent Process (PID: %d) about to fork...\n", getpid());

 pid = fork();

 if (pid < 0) {
 // Fork failed
 perror("fork failed");
 exit(EXIT_FAILURE);
 }

 if (pid == 0) {
 // Child process executes this block
 printf("\n[CHILD] I am the child process!\n");
 printf("[CHILD] My PID: %d\n", getpid());
 printf("[CHILD] My Parent's PID: %d\n", getppid());

 // Child does some work
 printf("[CHILD] Performing task...\n");
 for (int i = 1; i <= 3; i++) {
 printf("[CHILD] Working... %d/3\n", i);
 sleep(1);
 }

 printf("[CHILD] Task complete. Exiting with status 0.\n");
 exit(0); // Child exits, becomes zombie until parent reaps
 } 
 else {
 // Parent process executes this block
 printf("\n[PARENT] I am the parent process!\n");
 printf("[PARENT] My PID: %d\n", getpid());
 printf("[PARENT] My child's PID: %d\n", pid);

 // Parent waits for child to complete
 printf("[PARENT] Waiting for child to complete...\n");
 wait(&status); // Parent blocks until child terminates

 if (WIFEXITED(status)) {
 printf("[PARENT] Child exited with status: %d\n", WEXITSTATUS(status));
 }

 printf("[PARENT] Child has been reaped (zombie eliminated)\n");
 }
}

void demonstrate_multi_process() {
 printf("\n=== Multi-Process Demo ===\n\n");

 pid_t pid1, pid2;

 printf("Creating two child processes...\n");

 pid1 = fork();

 if (pid1 == 0) {
 // First child
 printf("[Child 1] PID: %d, executing calculation task\n", getpid());
 printf("[Child 1] Computing sum of 1 to 100...\n");
 int sum = 0;
 for (int i = 1; i <= 100; i++) sum += i;
 printf("[Child 1] Result: %d\n", sum);
 exit(0);
 }

 pid2 = fork();

 if (pid2 == 0 && pid1 > 0) {
 // Second child (only if fork succeeded)
 printf("[Child 2] PID: %d, executing I/O task\n", getpid());
 printf("[Child 2] Simulating file write operation...\n");
 sleep(1);
 printf("[Child 2] Write complete\n");
 exit(0);
 }

 // Parent waits for both children
 printf("[Parent] Waiting for children...\n");
 wait(NULL);
 wait(NULL);
 printf("[Parent] Both children completed\n");
}

int main() {
 printf("Operating System: Process Management\n");
 printf("Concept: Process Creation & Scheduling\n\n");

 demonstrate_process_creation();
 sleep(1);
 demonstrate_multi_process();

 printf("\n=== Demo Complete ===\n");
 return 0;
}
